7792   MinProfitableTripCount = ElementCount::getFixed(0);
7793   Value *CheckMinIters = createIterationCountCheck(
7794       VectorPH, ForEpilogue ? EPI.EpilogueVF : EPI.MainLoopVF,
7795       ForEpilogue ? EPI.EpilogueUF : EPI.MainLoopUF);
7796 
7797   BasicBlock *const TCCheckBlock = VectorPH;
7798   if (!ForEpilogue)
7799     TCCheckBlock->setName("vector.main.loop.iter.check");
7800 
7801   // Create new preheader for vector loop.
7802   VectorPH = SplitBlock(TCCheckBlock, TCCheckBlock->getTerminator(),
7803                         static_cast<DominatorTree *>(nullptr), LI, nullptr,
7804                         "vector.ph");
7805   if (ForEpilogue) {
7806     // Save the trip count so we don't have to regenerate it in the
7807     // vec.epilog.iter.check. This is safe to do because the trip count
7808     // generated here dominates the vector epilog iter check.
7809     EPI.TripCount = Count;
7810   } else {
7811     VectorPHVPBB = replaceVPBBWithIRVPBB(VectorPHVPBB, VectorPH);
7812   }
