7814   if (ForEpilogue && isEpilogueTailFolded) {
7815     BranchInst &BI = *BranchInst::Create(Bypass, VectorPH, Builder.getFalse());
7816     ReplaceInstWithInst(TCCheckBlock->getTerminator(), &BI);
